import { useState } from "react";

export default function TodoApp() {
  const [text, setText] = useState("");
  const [filter, setFilter] = useState("all");
  const [todos, setTodos] = useState([]);

  function addTodo() {
    if (!text.trim()) return;

    setTodos([
      ...todos,
      {
        id: Date.now(),
        text,
        done: false,
      },
    ]);

    setText("");
  }

  function toggleTodo(id) {
    setTodos(
      todos.map(todo =>
        todo.id === id
          ? { ...todo, done: !todo.done }
          : todo
      )
    );
  }

  const visibleTodos = todos.filter(todo =>
    filter === "all"
      ? true
      : filter === "active"
      ? !todo.done
      : todo.done
  );

  const remaining = todos.filter(todo => !todo.done).length;

  return (
    <main>
      <h1>📝 Todo App</h1>

      <form
        onSubmit={e => {
          e.preventDefault();
          addTodo();
        }}
      >
        <input
          value={text}
          placeholder="What needs to be done?"
          onChange={e => setText(e.target.value)}
        />

        <button>Add</button>
      </form>

      <fieldset>
        <legend>Show</legend>

        <label>
          <input
            type="radio"
            name="filter"
            checked={filter === "all"}
            onChange={() => setFilter("all")}
          />
          All
        </label>

        <label>
          <input
            type="radio"
            name="filter"
            checked={filter === "active"}
            onChange={() => setFilter("active")}
          />
          Active
        </label>

        <label>
          <input
            type="radio"
            name="filter"
            checked={filter === "done"}
            onChange={() => setFilter("done")}
          />
          Done
        </label>
      </fieldset>

      <p>{remaining} remaining</p>

      <ul>
        {visibleTodos.map(todo => (
          <li key={todo.id}>
            <label>
              <input
                type="checkbox"
                checked={todo.done}
                onChange={() => toggleTodo(todo.id)}
              />

              {todo.done ? <s>{todo.text}</s> : todo.text}
            </label>
          </li>
        ))}
      </ul>
    </main>
  );
}
